from elasticsearch import Elasticsearch
from flask import Flask, request, jsonify

app = Flask(__name__)

es = Elasticsearch(['localhost:9200'])

@app.route('/aggregate', methods=['POST'])
def aggregate():
    req_data = request.get_json()
    
    index_name = req_data.get('index', '_all')
    script_code = req_data['script']
    agg_name = req_data.get('agg_name', 'custom_agg')
    field = req_data.get('field', '_source')
    
    query = {
        "size": 0,
        "aggs": {
            agg_name: {
                "scripted_metric": {
                    "init_script": {
                        "inline": "state.transactions = []"
                    },
                    "map_script": {
                        "inline": script_code
                    },
                    "combine_script": {
                        "inline": "return state"
                    },
                    "reduce_script": {
                        "inline": "return states"
                    }
                }
            }
        }
    }
    
    result = es.search(index=index_name, body=query)
    
    return jsonify(result['aggregations'])

