@app.route('/execute', methods=['POST'])
def execute():
    req_data = request.get_json()
    
    index_name = req_data.get('index', '_all')
    script_code = req_data['script']
    operation = req_data.get('operation', 'search')
    
    if operation == 'search':
        body = {
            "query": {
                "match_all": {}
            },
            "script_fields": {
                "result": {
                    "script": {
                        "inline": script_code
                    }
                }
            }
        }
        result = es.search(index=index_name, body=body)
    elif operation == 'aggregate':
        body = {
            "size": 0,
            "aggs": {
                "custom": {
                    "scripted_metric": {
                        "map_script": {
                            "inline": script_code
                        }
                    }
                }
            }
        }
        result = es.search(index=index_name, body=body)
    else:
        result = {"error": "Unknown operation"}
    
    return jsonify(result)

